import fs from 'fs';
import path from 'path';
import crypto from 'crypto';

const root = process.cwd();
const srcRoot = path.join(root, 'agent-system-docs');
const outPath = path.join(root, 'merge-check-report-v2.json');

function sha256(filePath) {
  const data = fs.readFileSync(filePath);
  return crypto.createHash('sha256').update(data).digest('hex');
}

function walk(dir) {
  const out = [];
  const stack = [dir];
  while (stack.length) {
    const cur = stack.pop();
    for (const ent of fs.readdirSync(cur, { withFileTypes: true })) {
      const full = path.join(cur, ent.name);
      const relFromSrc = path.relative(srcRoot, full).split(path.sep).join('/');
      if (relFromSrc.startsWith('dist/')) continue;
      if (relFromSrc.startsWith('.git/')) continue;
      if (ent.isDirectory()) {
        stack.push(full);
      } else if (ent.isFile()) {
        out.push(full);
      }
    }
  }
  return out;
}

if (!fs.existsSync(srcRoot)) {
  fs.writeFileSync(outPath, JSON.stringify({ status: 'src_missing' }, null, 2));
  process.exit(0);
}

const srcFiles = walk(srcRoot);
const missing = [];
const different = [];

for (const srcFile of srcFiles) {
  const rel = path.relative(srcRoot, srcFile).split(path.sep).join('/');
  const dest = path.join(root, rel);
  if (!fs.existsSync(dest)) {
    missing.push(rel);
    continue;
  }
  if (!fs.statSync(dest).isFile()) {
    missing.push(rel);
    continue;
  }
  const hs = sha256(srcFile);
  const hd = sha256(dest);
  if (hs !== hd) {
    different.push(rel);
  }
}

const report = {
  status: 'ok',
  excluded: ['dist/**', '.git/**'],
  source_file_count: srcFiles.length,
  missing_count: missing.length,
  different_hash_count: different.length,
  missing_list: missing,
  different_hash_list: different,
  safe_to_delete_agent_system_docs: missing.length === 0
};

fs.writeFileSync(outPath, JSON.stringify(report, null, 2));

